INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 1, 62, "カリン", 1, 1, 1000001, 3.414, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ミッションをクリアして、\n報酬をゲットしましょう！", "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 2, 62, "カリン", 1, 1, 1000002, 3.099, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("受け取ることができる\n報酬があるようです\n確認してみてください", "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 3, 63, "カリン", 1, 1, 1000003, 2.801, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("報酬がもらえますよ！\nチェックしてみてください", "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 4, 63, "カリン", 1, 2, 1000004, 0.0, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2025/01/31 12:00:00", 1, "2030/01/01 14:59:59", -363.0, 5, 64, "カリン", 1, 2, 1000005, 2.12, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", -363.0, 6, 64, "カリン", 1, 1, 1000006, 1.68, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2025/01/31 12:00:00", 1, "2030/01/01 14:59:59", -363.0, 7, 64, "カリン", 1, 2, 1000007, 2.33, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", "2025/01/31 12:00:00", 7, "2030/01/01 14:59:59", -285.0, 101, 61, "ラビリスタ", 10201, 3, 1020101, 5.18, -6.0, 133701);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", "2025/01/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "クリスティーナ", 10201, 1, 1020102, 8.77, -2.0, 133901);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", "2025/01/31 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 301, 61, "ネネカ", 10201, 6, 1020103, 15.5, 0.0, 133801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", "2025/02/28 12:00:00", 5, "2030/01/01 14:59:59", -285.0, 101, 61, "ランファ", 10202, 2, 1020201, 9.061, 0.0, 134301);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", "2025/02/28 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "チカ", 10202, 1, 1020202, 7.699, 0.0, 134401);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", "2025/03/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "アオイ", 10203, 1, 1020301, 8.595, 0.0, 134601);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", "2025/03/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "クローチェ", 10203, 1, 1020302, 7.758, 0.0, 134501);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", "2025/04/30 12:00:00", 6, "2030/01/01 14:59:59", -285.0, 101, 61, "ルイズマリー", 10204, 2, 1020401, 7.0, 0.0, 132302);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", "2025/04/30 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "イロハ", 10204, 1, 1020402, 7.904, 0.0, 132402);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", "2025/04/30 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 301, 61, "ソノ", 10204, 4, 1020403, 8.487, 0.0, 132502);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", "2025/05/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "カノン", 10205, 1, 1020502, 8.763, 0.0, 134901);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", "2025/05/31 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 201, 61, "ツムギ", 10205, 1, 1020503, 6.417, 0.0, 134801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", "2025/06/30 12:00:00", 7, "2030/01/01 14:59:59", -285.0, 101, 61, "エリス", 10206, 3, 1020601, 10.335, 0.0, 135001);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", "2025/06/30 12:00:00", 4, "2030/01/01 14:59:59", -285.0, 201, 61, "シェフィ", 10206, 2, 1020602, 6.281, 0.0, 135101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", "2025/06/30 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 301, 61, "プレシア", 10206, 1, 1020603, 12.244, 0.0, 135201);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", "2025/07/31 12:00:00", 8, "2030/01/01 14:59:59", -285.0, 101, 61, "クリア", 10207, 2, 1020701, 6.339, 0.0, 135301);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", "2025/07/31 12:00:00", 9, "2030/01/01 14:59:59", -285.0, 201, 61, "アネモネ", 10207, 7, 1020702, 8.184, 0.0, 135401);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", "2025/08/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "アイラ", 10208, 9, 1020801, 3.906, 0.0, 129101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", "2025/08/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "シナツ", 10208, 1, 1020802, 14.465, 0.0, 129201);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", "2025/08/31 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 301, 61, "ヒヨリ", 10208, 4, 1020803, 8.662, 0.0, 100101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", "2025/08/31 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 401, 61, "レイ", 10208, 1, 1020804, 10.915, 0.0, 100301);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", "2025/09/30 12:00:00", 7, "2030/01/01 14:59:59", -285.0, 101, 61, "ユキノ", 10209, 1, 1020901, 6.042, 0.0, 135802);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", "2025/09/30 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 201, 61, "サツキ", 10209, 4, 1020902, 9.402, 0.0, 135903);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", "2025/09/30 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 301, 61, "ルルィ", 10209, 8, 1020903, 8.16, 0.0, 136902);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", "2025/10/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "カスミ", 10210, 3, 1021001, 5.0, 0.0, 137401);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", "2025/10/31 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 201, 61, "アラクネ", 10210, 4, 1021002, 8.12, 0.0, 136001);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", "2025/10/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 301, 61, "ナーナ", 10210, 4, 1021003, 6.386, 0.0, 136202);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", "2025/11/30 12:00:00", 4, "2030/01/01 14:59:59", -285.0, 101, 61, "ユイ", 10211, 3, 1021101, 7.438, 0.0, 136402);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", "2025/11/30 12:00:00", 5, "2030/01/01 14:59:59", -285.0, 201, 61, "ミソラ", 10211, 1, 1021102, 8.35, 0.0, 136302);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", "2025/12/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "シズル", 10212, 1, 1021201, 5.0, 0.0, 136501);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", "2025/12/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "リノ", 10212, 1, 1021202, 5.25, 0.0, 137902);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", "2025/12/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 301, 61, "ラビリスタ", 10212, 1, 1021203, 7.5, 0.0, 106801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", "2026/01/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "ライラエル", 10213, 1, 1021301, 8.204, 0.0, 126501);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", "2026/01/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 201, 61, "ネフィ＝ネラ", 10213, 1, 1021302, 7.176, 0.0, 129701);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", "2026/01/31 12:00:00", 5, "2030/01/01 14:59:59", -285.0, 301, 61, "ヴァイオレット", 10213, 1, 1021303, 8.602, 0.0, 133101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", "2026/02/06 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 102, 61, "ライラエル", 10213, 1, 1021304, 10.14, 0.0, 138101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", "2026/02/06 12:00:00", 7, "2030/01/01 14:59:59", -285.0, 202, 61, "ネフィ＝ネラ", 10213, 1, 1021305, 10.152, 0.0, 138201);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", "2026/02/06 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 302, 61, "ヴァイオレット", 10213, 4, 1021306, 9.688, 0.0, 138001);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", "2026/02/12 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 401, 61, "ペコリーヌ", 10213, 2, 1021307, 5.928, 0.0, 138301);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", "2026/02/28 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "ワカナ", 10214, 4, 1021401, 9.19, 0.0, 138702);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", "2026/02/28 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 201, 61, "シオリ", 10214, 1, 1021402, 8.724, 0.0, 138802);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", "2026/03/31 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 101, 61, "グレイス", 10215, 4, 1021501, 7.758, 0.0, 138902);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", "2026/03/31 12:00:00", 4, "2030/01/01 14:59:59", -285.0, 201, 61, "キョウカ", 10215, 6, 1021502, 6.375, 0.0, 139002);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", "2026/03/31 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 301, 61, "ルルィ", 10215, 6, 1021503, 6.173, 0.0, 136902);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", "2026/04/30 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 101, 61, "ミホ", 10216, 6, 1021601, 4.202, 0.0, 139202);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", "2026/04/30 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 201, 61, "マホ", 10216, 6, 1021602, 2.842, 0.0, 139302);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", "2026/04/30 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 301, 61, "エリカ", 10216, 4, 1021603, 4.598, 0.0, 139402);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", "2026/05/31 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 101, 61, "リリ", 10217, 4, 1021701, 6.533, 0.0, 125802);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", "2026/05/31 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 301, 61, "プレシア", 10217, 3, 1021702, 5.0, 0.0, 126102);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", "2026/05/31 12:00:00", 4, "2030/01/01 14:59:59", -285.0, 201, 61, "クリア", 10217, 3, 1021703, 5.214, 0.0, 126002);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", "2026/05/31 12:00:00", 3, "2030/01/01 14:59:59", -285.0, 102, 61, "リリ", 10217, 1, 1021704, 8.781, 0.0, 139501);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", "2026/05/31 12:00:00", 1, "2030/01/01 14:59:59", -285.0, 202, 61, "クリア", 10217, 2, 1021705, 6.529, 0.0, 139601);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", "2026/05/31 12:00:00", 2, "2030/01/01 14:59:59", -285.0, 302, 61, "プレシア", 10217, 3, 1021706, 3.195, 0.0, 139701);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2026/04/10 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 1, 62, "カリン", 2, 1, 2000001, 3.414, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ミッションをクリアして、\n報酬をゲットしましょう！", "2026/04/10 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 2, 62, "カリン", 2, 1, 2000002, 3.099, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("受け取ることができる\n報酬があるようです\n確認してみてください", "2026/04/10 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 3, 63, "カリン", 2, 1, 2000003, 2.801, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("報酬がもらえますよ！\nチェックしてみてください", "2026/04/10 12:00:00", 2, "2030/01/01 14:59:59", -416.5, 4, 63, "カリン", 2, 2, 2000004, 0.0, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2026/04/10 12:00:00", 1, "2030/01/01 14:59:59", -363.0, 5, 64, "カリン", 2, 2, 2000005, 2.12, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2026/04/10 12:00:00", 2, "2030/01/01 14:59:59", -363.0, 6, 64, "カリン", 2, 1, 2000006, 1.68, 0.0, 190801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES ("いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2026/04/10 12:00:00", 1, "2030/01/01 14:59:59", -363.0, 7, 64, "カリン", 2, 2, 2000007, 2.33, 0.0, 190801);
